/**
 * Minimal `browser.*` polyfill for Chrome.
 *
 * We only implement what this extension needs (storage + runtime).
 *
 * Why:
 * - Firefox exposes `browser` natively.
 * - Chrome exposes `chrome` and does not guarantee `browser`.
 */

type WebExtGlobal = typeof globalThis & {
  chrome?: {
    runtime?: unknown;
    storage?: unknown;
  };
  browser?: {
    runtime?: unknown;
    storage?: unknown;
  };
};

export function ensureWebExtPolyfill(): void {
  const g = globalThis as WebExtGlobal;

  if (typeof g.browser !== "undefined") {
    return;
  }

  if (typeof g.chrome === "undefined") {
    return;
  }

  // Keep it thin: forward to chrome.*.
  g.browser = {
    runtime: g.chrome.runtime,
    storage: g.chrome.storage
  };
}
